!function(){var e=document.querySelectorAll(".reveal");if("IntersectionObserver"in window){var n=new IntersectionObserver(function(e){e.forEach(function(e){e.isIntersecting&&(e.target.classList.add("visible"),n.unobserve(e.target))})},{threshold:.12});e.forEach(function(e){n.observe(e)})}else e.forEach(function(e){e.classList.add("visible")})}();